SELECT presPenetration_sampled, BioPenetration_failed, penSampledTotal
FROM QC_Data
WHERE ChargeNumber = {[.]../Charge Number}

SELECT presredrill, bioredrill, preTotal as redrillTotal
FROM QC_Data
WHERE ChargeNumber = {[.]../Charge Number}

SELECT presFinal, BioFinal, bioTotal as finalTotal
FROM QC_Data
WHERE ChargeNumber = {[.]../Charge Number}

SELECT presAssay, bioAssay, presFinal as AssayTotal
FROM QC_Data
WHERE ChargeNumber = {[.]../Charge Number}

SELECT Step9StartVol
FROM Charge_Data
WHERE ChargeNumber = {[.]../Charge Number}

SELECT Step1StartVol - Step9StartVol
FROM Charge_Data
WHERE ChargeNumber = {[.]../Charge Number}

SELECT Step1StartVol
FROM Charge_Data
WHERE ChargeNumber = {[.]../Charge Number}

SELECT QCOperator
FROM QC_Data
WHERE ChargeNumber = {[.]../Charge Number}

eventScripts.script:
if not initialChange:
	if currentValue.value == 1:
		print "MSR Mark Charge In Cylinder Failed - Generate Problem Log"
		path = "ProblemLogMarkCharge"
		cNum = system.tag.readBlocking("[.]Charge Number")[0].value
		pType = 'Inventory Status Update - Charge Started'
		pDesc = system.tag.readBlocking("[.]In Cyl Response")[0].value

		params = {'ChargeNumber':cNum,'ProblemType':pType,'ProblemDesc':pDesc}
		system.db.runNamedQuery(path,parameters = params)


if not initialChange:
	if currentValue.value == 1:
		print "MSR Mark Charge Out of Cylinder Failed - Generate Problem Log"
		path = "ProblemLogMarkCharge"
		cNum = system.tag.readBlocking("[.]Charge Number")[0].value
		pType = 'Inventory Status Update - Charge Finished'
		pDesc = system.tag.readBlocking("[.]Out Cyl Response")[0].value

		params = {'ChargeNumber':cNum,'ProblemType':pType,'ProblemDesc':pDesc}
		system.db.runNamedQuery(path,parameters = params)

